const API_BASE="https://kapanlibur-api.krisdev.my.id";function getLang(){return localStorage.getItem("lang")||"id"}async function fetchTodayHoliday(e){const n=e||getLang();try{const t=await fetch(`${API_BASE}/v1/holidays/current?lang=${n}`);if(!t.ok)throw new Error(`HTTP error! status: ${t.status}`);const r=await t.json();return r.success?{data:r.data,message:r.message}:null}catch(t){return console.error("Error fetching today holiday:",t),"error"}}async function fetchNextHoliday(e){const n=e||getLang();try{const t=await fetch(`${API_BASE}/v1/holidays/next?lang=${n}`);if(!t.ok)throw new Error(`HTTP error! status: ${t.status}`);const r=await t.json();return r.success?{data:r.data,message:r.message}:null}catch(t){return console.error("Error fetching next holiday:",t),"error"}}function formatDate(e,n){const t=new Date(e),r=n==="id"?"id-ID":"en-US";return t.toLocaleDateString(r,{weekday:"long",day:"numeric",month:"long",year:"numeric"})}function formatCurrentDate(e){const n=new Date,t=e==="id"?"id-ID":"en-US";return n.toLocaleDateString(t,{day:"numeric",month:"long",year:"numeric"})}async function fetchSuggestions(e){const n=e||getLang();try{const t=await fetch(`${API_BASE}/v1/holidays/suggestions?lang=${n}`);if(!t.ok)throw new Error(`HTTP error! status: ${t.status}`);const r=await t.json();return r.success?r.data.suggestions:[]}catch(t){return console.error("Error fetching suggestions:",t),"error"}}function formatDateRange(e,n,t){const r=new Date(e),a=new Date(n),o=t==="id"?"id-ID":"en-US",s=r.toLocaleDateString(o,{day:"numeric",month:"short"}),c=a.toLocaleDateString(o,{day:"numeric",month:"short"});return`${s} - ${c}`}
